CREATE OR REPLACE FUNCTION aionn_catalog_seed_color_label(p_color TEXT, p_option TEXT)
RETURNS TEXT
LANGUAGE plpgsql
AS $$
DECLARE
    normalized TEXT := lower(coalesce(p_color, ''));
    option_number INTEGER := COALESCE(NULLIF(regexp_replace(coalesce(p_option, ''), '\D', '', 'g'), '')::INTEGER, 1);
    palette TEXT[] := ARRAY['Đen', 'Trắng', 'Xám', 'Xanh biển', 'Nâu'];
BEGIN
    IF option_number > 1 THEN
        RETURN palette[((option_number - 1) % array_length(palette, 1)) + 1];
    END IF;

    IF normalized IN ('black', 'den', 'đen') THEN
        RETURN 'Đen';
    ELSIF normalized IN ('white', 'trang', 'trắng') THEN
        RETURN 'Trắng';
    ELSIF normalized IN ('grey', 'gray', 'xam', 'xám') THEN
        RETURN 'Xám';
    ELSIF normalized IN ('navy', 'blue', 'xanh bien', 'xanh biển') THEN
        RETURN 'Xanh biển';
    ELSIF normalized IN ('brown', 'nau', 'nâu') THEN
        RETURN 'Nâu';
    ELSIF p_color IS NOT NULL AND btrim(p_color) <> '' THEN
        RETURN p_color;
    END IF;

    RETURN palette[((option_number - 1) % array_length(palette, 1)) + 1];
END;
$$;

CREATE OR REPLACE FUNCTION aionn_catalog_seed_variant_size(p_size TEXT, p_option TEXT, p_is_shoe BOOLEAN)
RETURNS TEXT
LANGUAGE plpgsql
AS $$
DECLARE
    option_number INTEGER := COALESCE(NULLIF(regexp_replace(coalesce(p_option, ''), '\D', '', 'g'), '')::INTEGER, 1);
    apparel_sizes TEXT[] := ARRAY['S', 'M', 'L', 'XL'];
    shoe_sizes TEXT[] := ARRAY['39', '40', '41', '42'];
BEGIN
    IF option_number = 1 AND p_size IS NOT NULL AND btrim(p_size) <> '' THEN
        RETURN p_size;
    END IF;

    IF p_is_shoe THEN
        RETURN shoe_sizes[((option_number - 1) % array_length(shoe_sizes, 1)) + 1];
    END IF;

    RETURN apparel_sizes[((option_number - 1) % array_length(apparel_sizes, 1)) + 1];
END;
$$;

CREATE OR REPLACE FUNCTION aionn_catalog_seed_variant_attributes(
    p_attributes JSONB,
    p_category_ids JSONB,
    p_option TEXT
) RETURNS JSONB
LANGUAGE plpgsql
AS $$
DECLARE
    attrs JSONB := COALESCE(p_attributes, '{}'::jsonb);
    option_number INTEGER := COALESCE(NULLIF(regexp_replace(coalesce(p_option, ''), '\D', '', 'g'), '')::INTEGER, 1);
    is_fashion BOOLEAN := p_category_ids ? 'CAT_FAS' OR p_category_ids ? 'CAT_MCL' OR p_category_ids ? 'CAT_WCL';
    is_shoe BOOLEAN := p_category_ids ? 'CAT_SHO';
    is_electronics BOOLEAN := p_category_ids ? 'CAT_ELE' OR p_category_ids ? 'CAT_ACC' OR p_category_ids ? 'CAT_LAP'
        OR p_category_ids ? 'CAT_PHO' OR p_category_ids ? 'CAT_SMH' OR p_category_ids ? 'CAT_SML'
        OR p_category_ids ? 'CAT_SMS' OR p_category_ids ? 'CAT_SMC';
    is_home BOOLEAN := p_category_ids ? 'CAT_HOK' OR p_category_ids ? 'CAT_KAP' OR p_category_ids ? 'CAT_FUR';
    is_beauty BOOLEAN := p_category_ids ? 'CAT_HBE' OR p_category_ids ? 'CAT_SKN' OR p_category_ids ? 'CAT_VIT';
BEGIN
    IF is_fashion OR is_shoe THEN
        RETURN jsonb_build_object(
            'color', aionn_catalog_seed_color_label(attrs ->> 'color', p_option),
            'size', aionn_catalog_seed_variant_size(attrs ->> 'size', p_option, is_shoe)
        );
    ELSIF is_electronics THEN
        IF attrs ? 'storage' THEN
            RETURN jsonb_build_object(
                'storage', CASE
                    WHEN option_number = 1 THEN attrs ->> 'storage'
                    WHEN attrs ->> 'storage' = '128GB' THEN '256GB'
                    WHEN attrs ->> 'storage' = '256GB' THEN '512GB'
                    ELSE '128GB'
                END,
                'color', aionn_catalog_seed_color_label(attrs ->> 'color', p_option)
            );
        ELSIF attrs ? 'ram' OR attrs ? 'cpu' THEN
            RETURN jsonb_strip_nulls(jsonb_build_object(
                'cpu', attrs ->> 'cpu',
                'ram', CASE
                    WHEN option_number = 1 THEN attrs ->> 'ram'
                    WHEN attrs ->> 'ram' = '16GB' THEN '32GB'
                    WHEN attrs ->> 'ram' = '32GB' THEN '64GB'
                    ELSE COALESCE(attrs ->> 'ram', '16GB')
                END
            ));
        ELSE
            RETURN jsonb_build_object(
                'color', aionn_catalog_seed_color_label(attrs ->> 'color', p_option),
                'type', CASE WHEN option_number = 1 THEN 'Tiêu chuẩn' ELSE 'Cao cấp' END
            );
        END IF;
    ELSIF is_home THEN
        RETURN jsonb_build_object(
            'material', CASE WHEN option_number = 1 THEN 'Tiêu chuẩn' ELSE 'Cao cấp' END,
            'size', aionn_catalog_seed_variant_size(attrs ->> 'size', p_option, FALSE)
        );
    ELSIF is_beauty THEN
        RETURN jsonb_build_object(
            'volume', CASE WHEN option_number = 1 THEN '150ml' ELSE '250ml' END,
            'pack', CASE WHEN option_number = 1 THEN 'Tiêu chuẩn' ELSE 'Tiết kiệm' END
        );
    END IF;

    RETURN CASE WHEN attrs = '{}'::jsonb THEN jsonb_build_object('type', 'Tiêu chuẩn') ELSE attrs END;
END;
$$;

UPDATE product_variants pv
SET attribute_values = aionn_catalog_seed_variant_attributes(
    p.attributes,
    p.category_ids,
    pv.attribute_values ->> 'option'
)
FROM products p
WHERE p.product_id = pv.product_id
  AND pv.attribute_values ? 'option'
  AND pv.attribute_values ->> 'option' ~* '^option\s+\d+$';

DROP FUNCTION aionn_catalog_seed_variant_attributes(JSONB, JSONB, TEXT);
DROP FUNCTION aionn_catalog_seed_variant_size(TEXT, TEXT, BOOLEAN);
DROP FUNCTION aionn_catalog_seed_color_label(TEXT, TEXT);

