-- -----------------------------------------------------------------------------
-- Product-detail description enrichment for all seeded products.
-- -----------------------------------------------------------------------------
CREATE OR REPLACE FUNCTION aionn_catalog_seed_description(
    p_name TEXT,
    p_brand TEXT,
    p_category_ids JSONB,
    p_attributes JSONB
) RETURNS TEXT
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_category_ids ? 'CAT_ELE' OR p_category_ids ? 'CAT_ACC' OR p_category_ids ? 'CAT_LAP'
       OR p_category_ids ? 'CAT_PHO' OR p_category_ids ? 'CAT_SMH'
       OR p_category_ids ? 'CAT_SML' OR p_category_ids ? 'CAT_SMS' OR p_category_ids ? 'CAT_SMC' THEN
        RETURN
            'MÔ TẢ SẢN PHẨM' || E'\n' ||
            p_name || ' là sản phẩm công nghệ được tuyển chọn cho nhu cầu sử dụng hằng ngày, tập trung vào độ ổn định, trải nghiệm thao tác nhanh và thiết kế dễ phối với không gian sống hiện đại. Sản phẩm phù hợp cho người dùng cần một thiết bị bền bỉ, gọn gàng và có thể sử dụng lâu dài trong gia đình, văn phòng hoặc khi di chuyển.' || E'\n\n' ||
            'VÌ SAO BẠN AN TÂM KHI MUA TẠI AIONN' || E'\n\n' ||
            '- Sản phẩm thuộc hệ sinh thái ' || p_brand || ', được kiểm tra ngoại quan và chức năng trước khi bàn giao.' || E'\n' ||
            '- Hàng mới, đóng gói chắc chắn, có tem kiểm tra và thông tin sản phẩm rõ ràng.' || E'\n' ||
            '- Hỗ trợ xuất hóa đơn theo yêu cầu và lưu lịch sử đơn hàng trực tiếp trên tài khoản Aionn.' || E'\n' ||
            '- Chính sách bảo hành 12 tháng cho lỗi kỹ thuật từ nhà sản xuất, hỗ trợ đổi trả theo quy định của sàn.' || E'\n\n' ||
            'ĐIỂM NỔI BẬT' || E'\n\n' ||
            '- Thiết kế tối giản, dễ lắp đặt và dễ sử dụng ngay cả với người mới.' || E'\n' ||
            '- Tối ưu cho hiệu năng ổn định, hạn chế nóng máy và giảm hao pin trong quá trình sử dụng.' || E'\n' ||
            '- Kết nối nhanh, tương thích tốt với các thiết bị phổ biến trong hệ sinh thái nhà thông minh và phụ kiện công nghệ.' || E'\n' ||
            '- Vỏ ngoài chắc chắn, hoàn thiện bề mặt kỹ, hạn chế bám dấu vân tay và dễ vệ sinh.' || E'\n\n' ||
            'PHIÊN BẢN / PHÂN LOẠI' || E'\n\n' ||
            '- Bản tiêu chuẩn: phù hợp sử dụng hằng ngày, ưu tiên sự gọn nhẹ và chi phí hợp lý.' || E'\n' ||
            '- Bản cao cấp: bổ sung lựa chọn màu sắc, cấu hình hoặc phụ kiện mở rộng tùy từng đợt hàng.' || E'\n\n' ||
            'THÔNG SỐ THAM KHẢO' || E'\n\n' ||
            '- Thương hiệu: ' || p_brand || E'\n' ||
            '- Thuộc tính chính: ' || COALESCE(p_attributes::TEXT, '{}') || E'\n' ||
            '- Nguồn gốc: phân phối bởi gian hàng Aionn đã xác thực.' || E'\n' ||
            '- Bảo hành: 12 tháng theo chính sách nhà bán.' || E'\n\n' ||
            'LƯU Ý TRƯỚC KHI NHẬN HÀNG' || E'\n\n' ||
            '- Vui lòng quay video khi mở kiện hàng để đảm bảo đầy đủ quyền lợi hỗ trợ nếu phát sinh thiếu phụ kiện hoặc lỗi ngoại quan.' || E'\n' ||
            '- Kiểm tra đúng phiên bản, màu sắc và phụ kiện trước khi xác nhận đã nhận hàng.' || E'\n' ||
            '- Với sản phẩm đã bóc seal hoặc đã kích hoạt bảo hành điện tử, việc đổi trả sẽ áp dụng theo tình trạng thực tế và quy định của sàn.';
    ELSIF p_category_ids ? 'CAT_FAS' OR p_category_ids ? 'CAT_MCL' OR p_category_ids ? 'CAT_WCL' OR p_category_ids ? 'CAT_SHO' THEN
        RETURN
            'MÔ TẢ SẢN PHẨM' || E'\n' ||
            p_name || ' được thiết kế cho nhu cầu mặc và sử dụng hằng ngày, ưu tiên phom dáng dễ phối, chất liệu thoải mái và độ bền sau nhiều lần sử dụng. Sản phẩm phù hợp để đi học, đi làm, dạo phố hoặc làm món quà thực tế cho người thân.' || E'\n\n' ||
            'VÌ SAO BẠN AN TÂM KHI MUA TẠI AIONN' || E'\n\n' ||
            '- Gian hàng ' || p_brand || ' cung cấp thông tin size, màu và chất liệu rõ ràng để bạn dễ chọn đúng nhu cầu.' || E'\n' ||
            '- Sản phẩm được kiểm tra đường may, bề mặt chất liệu và đóng gói trước khi giao.' || E'\n' ||
            '- Hỗ trợ đổi trả theo chính sách nếu sản phẩm giao sai phân loại hoặc phát sinh lỗi từ nhà bán.' || E'\n' ||
            '- Đội ngũ CSKH hỗ trợ tư vấn size, cách bảo quản và xử lý đơn sau bán.' || E'\n\n' ||
            'ĐIỂM NỔI BẬT' || E'\n\n' ||
            '- Phom dáng dễ mặc, phù hợp nhiều độ tuổi và nhiều hoàn cảnh sử dụng.' || E'\n' ||
            '- Chất liệu được chọn để tạo cảm giác mềm, thoáng và hạn chế kích ứng khi mặc lâu.' || E'\n' ||
            '- Màu sắc cơ bản, dễ phối với tủ đồ hiện có.' || E'\n' ||
            '- Đường may và chi tiết hoàn thiện được gia cố ở các vị trí thường chịu lực.' || E'\n\n' ||
            'PHÂN LOẠI' || E'\n\n' ||
            '- Phân loại tiêu chuẩn: phù hợp sử dụng hằng ngày.' || E'\n' ||
            '- Phân loại cao cấp hoặc màu đặc biệt: phù hợp khi cần tạo điểm nhấn hoặc làm quà tặng.' || E'\n\n' ||
            'THÔNG TIN SẢN PHẨM' || E'\n\n' ||
            '- Thương hiệu: ' || p_brand || E'\n' ||
            '- Thuộc tính: ' || COALESCE(p_attributes::TEXT, '{}') || E'\n' ||
            '- Hướng dẫn bảo quản: giặt nhẹ, tránh ngâm lâu, phơi nơi thoáng mát và hạn chế sấy nhiệt cao.' || E'\n\n' ||
            'LƯU Ý TRƯỚC KHI NHẬN HÀNG' || E'\n\n' ||
            '- Vui lòng kiểm tra đúng size, màu và số lượng trước khi xác nhận đơn.' || E'\n' ||
            '- Màu sắc thực tế có thể chênh nhẹ do điều kiện ánh sáng và màn hình hiển thị.' || E'\n' ||
            '- Nếu cần đổi size, hãy giữ nguyên tem mác và bao bì trong tình trạng tốt nhất.';
    ELSIF p_category_ids ? 'CAT_HOK' OR p_category_ids ? 'CAT_KAP' OR p_category_ids ? 'CAT_FUR' THEN
        RETURN
            'MÔ TẢ SẢN PHẨM' || E'\n' ||
            p_name || ' là sản phẩm gia dụng/nội thất hướng tới trải nghiệm sống tiện nghi hơn, phù hợp cho căn hộ, văn phòng nhỏ hoặc không gian gia đình hiện đại. Thiết kế ưu tiên tính bền, dễ vệ sinh và dễ kết hợp với nhiều phong cách trang trí.' || E'\n\n' ||
            'VÌ SAO BẠN AN TÂM KHI MUA TẠI AIONN' || E'\n\n' ||
            '- Sản phẩm từ ' || p_brand || ' được mô tả rõ kích thước, chất liệu và công năng trước khi đặt hàng.' || E'\n' ||
            '- Đóng gói nhiều lớp nhằm hạn chế trầy xước hoặc móp méo trong quá trình vận chuyển.' || E'\n' ||
            '- Có hỗ trợ sau bán cho các vấn đề về phụ kiện, linh kiện hoặc hướng dẫn lắp đặt.' || E'\n' ||
            '- Chính sách đổi trả áp dụng khi sản phẩm lỗi kỹ thuật, bể vỡ do vận chuyển hoặc giao sai phân loại.' || E'\n\n' ||
            'ĐIỂM NỔI BẬT' || E'\n\n' ||
            '- Thiết kế gọn gàng, dễ bố trí trong nhiều diện tích phòng.' || E'\n' ||
            '- Vật liệu được chọn để cân bằng giữa độ bền, thẩm mỹ và chi phí sử dụng lâu dài.' || E'\n' ||
            '- Bề mặt dễ lau chùi, phù hợp môi trường sinh hoạt hằng ngày.' || E'\n' ||
            '- Công năng rõ ràng, hỗ trợ tối ưu không gian và giảm thao tác thừa.' || E'\n\n' ||
            'THÔNG SỐ / CHẤT LIỆU' || E'\n\n' ||
            '- Thương hiệu: ' || p_brand || E'\n' ||
            '- Thuộc tính: ' || COALESCE(p_attributes::TEXT, '{}') || E'\n' ||
            '- Khuyến nghị sử dụng: đặt ở nơi khô ráo, tránh va đập mạnh và tránh tiếp xúc nhiệt trực tiếp quá lâu.' || E'\n\n' ||
            'LƯU Ý TRƯỚC KHI NHẬN HÀNG' || E'\n\n' ||
            '- Vui lòng kiểm tra ngoại quan, góc cạnh và phụ kiện đi kèm ngay khi nhận hàng.' || E'\n' ||
            '- Nên quay video mở kiện để được hỗ trợ nhanh trong trường hợp thiếu linh kiện hoặc phát sinh hư hỏng.' || E'\n' ||
            '- Với sản phẩm cần lắp ráp, hãy đọc hướng dẫn trước khi siết chặt toàn bộ ốc vít.';
    ELSE
        RETURN
            'MÔ TẢ SẢN PHẨM' || E'\n' ||
            p_name || ' là sản phẩm được chọn lọc cho nhu cầu chăm sóc cá nhân và sử dụng hằng ngày. Sản phẩm tập trung vào sự tiện lợi, độ an toàn khi dùng đúng hướng dẫn và trải nghiệm ổn định trong suốt vòng đời sử dụng.' || E'\n\n' ||
            'VÌ SAO BẠN AN TÂM KHI MUA TẠI AIONN' || E'\n\n' ||
            '- Gian hàng ' || p_brand || ' cung cấp thông tin sản phẩm, phân loại và lưu ý sử dụng minh bạch.' || E'\n' ||
            '- Hàng được đóng gói cẩn thận, hạn chế móp méo và bảo vệ tốt trong quá trình vận chuyển.' || E'\n' ||
            '- Hỗ trợ tư vấn trước và sau mua nếu bạn cần kiểm tra thành phần, cách dùng hoặc chính sách đổi trả.' || E'\n' ||
            '- Đơn hàng được lưu trên hệ thống để thuận tiện tra cứu bảo hành và hỗ trợ sau bán.' || E'\n\n' ||
            'ĐIỂM NỔI BẬT' || E'\n\n' ||
            '- Dễ sử dụng, phù hợp với thói quen sinh hoạt hằng ngày.' || E'\n' ||
            '- Công thức/thiết kế ưu tiên tính ổn định và cảm giác thoải mái khi dùng đều đặn.' || E'\n' ||
            '- Bao bì rõ ràng, dễ bảo quản và thuận tiện khi mang theo.' || E'\n' ||
            '- Phù hợp làm quà tặng thực tế cho gia đình, bạn bè hoặc đồng nghiệp.' || E'\n\n' ||
            'THÔNG TIN SẢN PHẨM' || E'\n\n' ||
            '- Thương hiệu: ' || p_brand || E'\n' ||
            '- Thuộc tính: ' || COALESCE(p_attributes::TEXT, '{}') || E'\n' ||
            '- Hướng dẫn bảo quản: để nơi khô ráo, tránh ánh nắng trực tiếp và đậy kín sau khi dùng.' || E'\n\n' ||
            'LƯU Ý TRƯỚC KHI NHẬN HÀNG' || E'\n\n' ||
            '- Kiểm tra kỹ tem, bao bì và hạn sử dụng nếu có.' || E'\n' ||
            '- Vui lòng đọc hướng dẫn sử dụng trước khi dùng, đặc biệt với sản phẩm chăm sóc sức khỏe/làm đẹp.' || E'\n' ||
            '- Ngừng sử dụng và liên hệ bộ phận hỗ trợ nếu phát sinh dấu hiệu bất thường.';
    END IF;
END;
$$;

UPDATE products p
SET ai_description = aionn_catalog_seed_description(p.name, b.name, p.category_ids, p.attributes),
    updated_at = NOW()
FROM brands b
WHERE b.brand_id = p.brand_id;

DROP FUNCTION aionn_catalog_seed_description(TEXT, TEXT, JSONB, JSONB);

CREATE OR REPLACE FUNCTION aionn_catalog_seed_images(p_category_ids JSONB) RETURNS JSONB
LANGUAGE plpgsql
AS $$
BEGIN
    IF p_category_ids ? 'CAT_SMH' OR p_category_ids ? 'CAT_SML' OR p_category_ids ? 'CAT_SMS' OR p_category_ids ? 'CAT_SMC' THEN
        RETURN jsonb_build_array(
            'https://images.unsplash.com/photo-1558002038-1055907df827?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1565814636199-ae8133055c1c?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1621905251189-08b45d6a269e?auto=format&fit=crop&w=900&q=80'
        );
    ELSIF p_category_ids ? 'CAT_ELE' OR p_category_ids ? 'CAT_ACC' OR p_category_ids ? 'CAT_LAP' OR p_category_ids ? 'CAT_PHO' THEN
        RETURN jsonb_build_array(
            'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1583394838336-acd977736f90?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1511707171634-5f897ff02aa9?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?auto=format&fit=crop&w=900&q=80'
        );
    ELSIF p_category_ids ? 'CAT_FAS' OR p_category_ids ? 'CAT_MCL' OR p_category_ids ? 'CAT_WCL' OR p_category_ids ? 'CAT_SHO' THEN
        RETURN jsonb_build_array(
            'https://images.unsplash.com/photo-1521572267360-ee0c2909d518?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1509319117193-57bab727e09d?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1549298916-b41d501d3772?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1606107557195-0e29a4b5b4aa?auto=format&fit=crop&w=900&q=80'
        );
    ELSIF p_category_ids ? 'CAT_HOK' OR p_category_ids ? 'CAT_KAP' OR p_category_ids ? 'CAT_FUR' THEN
        RETURN jsonb_build_array(
            'https://images.unsplash.com/photo-1524758631624-e2822e304c36?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1586023492125-27b2c045efd7?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1584269600464-37b1b58a9fe7?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1588854337236-6889d631faa8?auto=format&fit=crop&w=900&q=80'
        );
    ELSE
        RETURN jsonb_build_array(
            'https://images.unsplash.com/photo-1608248597279-f99d160bfcbc?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1556228578-0d85b1a4d571?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1576091160550-2173dba999ef?auto=format&fit=crop&w=900&q=80',
            'https://images.unsplash.com/photo-1584017911766-d451b3d0e843?auto=format&fit=crop&w=900&q=80'
        );
    END IF;
END;
$$;

UPDATE products
SET image_list = aionn_catalog_seed_images(category_ids),
    updated_at = NOW();

DROP FUNCTION aionn_catalog_seed_images(JSONB);
